def caesar(s, k):
    k = k % 26
    res = []
    for c in s:
        if 'a' <= c <= 'z':
            res.append(chr((ord(c) - ord('a') + k) % 26 + ord('a')))
        elif 'A' <= c <= 'Z':
            res.append(chr((ord(c) - ord('A') + k) % 26 + ord('A')))
        else:
            res.append(c)
    return ''.join(res)
